{"content":"import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    iterator = iter(tasks)
    running: set[asyncio.Task[None]] = set()
    cancelling = False

    def start_next() -> bool:
        nonlocal cancelling
        if cancelling:
            return False
        try:
            fn = next(iterator)
        except StopIteration:
            return False
        running.add(asyncio.create_task(fn()))
        return True

    for _ in range(min(max_concurrent, len(tasks))):
        if not start_next():
            break

    try:
        while running:
            done, pending = await asyncio.wait(
                running,
                return_when=asyncio.FIRST_COMPLETED,
            )
            running = set(pending)

            for task in done:
                task.result()

            while len(running) < max_concurrent and start_next():
                pass
    except BaseException:
        cancelling = True
        for task in running:
            task.cancel()
        if running:
            await asyncio.gather(*running, return_exceptions=True)
        raise
